        eig_vec_kernel[grid](A, eigenvals, eigenvecs, n, batch_size, BLOCK_SIZE=BLOCK_SIZE)

    # Normalize eigenvectors
    for i in range(batch_size):
        for j in range(n):
            norm = torch.norm(eigenvecs[i, j, :])
            if norm > 0:
                eigenvecs[i, j, :] /= norm

